<template>  <ElDialog    v-model="dialogVisible"    width="95vw"    top="4vh"    destroy-on-close    class="fs-create-dialog"    :show-close="false"    @opened="onOpened"  >    <div      v-if="billType"      class="fs-create-header"      :class="{ 'is-residual': billType === '残值结算单' }"    >      <span class="fs-create-header-title">提交{{ billType }}申请</span>      <button type="button" class="fs-create-close" @click="dialogVisible = false">        <ArtSvgIcon icon="ri:close-line" />      </button>    </div>    <div v-if="billType" class="fs-create-steps">      <div class="fs-create-step" :class="stepClass(1)">        <span class="fs-create-step-num">{{ step > 1 ? '✓' : '1' }}</span>        <span>请选结算车辆</span>      </div>      <div class="fs-create-step-line" :class="{ 'is-done': step > 1 }" />      <div class="fs-create-step" :class="stepClass(2)">        <span class="fs-create-step-num">2</span>        <span>{{ billType }}</span>      </div>    </div>    <template v-if="step === 1 && billType">      <div class="fs-create-toolbar">        <ElInput          v-model="search"          placeholder="车牌号 / 自编号 / 车型"          clearable          style="width: 220px"        />        <ElButton @click="search = ''">重置</ElButton>        <span class="fs-create-selected-hint"          >已选 <b>{{ selectedIds.size }}</b> 辆</span        >      </div>      <div class="fs-create-body">        <table class="fs-create-table">          <thead>            <tr>              <th>                <ElCheckbox                  :model-value="allChecked"                  :indeterminate="someChecked && !allChecked"                  @change="toggleAll"                />              </th>              <th>序号</th>              <th>入库日期</th>              <th>自编号</th>              <th>车牌号</th>              <th>车型</th>              <th>实际重量(吨)</th>              <th v-if="isService">服务费合计</th>              <th>单车总金额(元)</th>            </tr>          </thead>          <tbody>            <tr              v-for="(v, i) in filteredCandidates"              :key="v.id"              class="fs-create-row"              :class="{ 'is-selected': selectedIds.has(v.id) }"              @click="toggleVehicle(v.id)"            >              <td @click.stop>                <ElCheckbox :model-value="selectedIds.has(v.id)" @change="toggleVehicle(v.id)" />              </td>              <td>{{ i + 1 }}</td>              <td>{{ v.inbound_date }}</td>              <td>{{ v.self_no }}</td>              <td class="fs-plate">{{ v.plate }}</td>              <td>{{ v.vehicle_model }}</td>              <td>{{ v.actual_weight.toFixed(2) }}</td>              <td v-if="isService">{{ computeTotals(v).svcTotal.toFixed(2) }}</td>              <td class="fs-amount">{{ computeTotals(v).autoTotal.toFixed(2) }}</td>            </tr>          </tbody>        </table>      </div>    </template>    <template v-else-if="step === 2 && billType">      <div class="fs-create-meta">        <span>          申请类型：          <span            class="fs-tag"            :style="{              color: SETTLEMENT_BILL_TYPE_CONFIG[billType].color,              background: SETTLEMENT_BILL_TYPE_CONFIG[billType].bg            }"            >{{ billType }}</span          >        </span>        <span          >车辆数量：<b>{{ selectedVehicles.length }} 辆</b></span        >        <span          >预计合计：<b class="fs-amount">¥ {{ grandTotal.toFixed(2) }}</b></span        >      </div>      <div class="fs-create-body">        <table class="fs-create-table">          <thead>            <tr>              <th>序号</th>              <th>车牌号</th>              <th>整备质量(吨)</th>              <th>实际重量(吨)</th>              <th>残值单价</th>              <th>预计支付残值</th>              <th v-if="isService">服务费合计</th>              <th>单车总金额(元)</th>              <th>修改说明</th>              <th>操作</th>            </tr>          </thead>          <tbody>            <tr v-for="(v, i) in selectedVehicles" :key="v.id">              <td>{{ i + 1 }}</td>              <td class="fs-plate">{{ v.plate }}</td>              <td>{{ v.std_weight.toFixed(3) }}</td>              <td class="fs-edit-cell">                <ElInputNumber                  :model-value="getNum(v, 'actual_weight')"                  :controls="false"                  size="small"                  @update:model-value="(val) => setNum(v.id, 'actual_weight', Number(val))"                />              </td>              <td class="fs-edit-cell">                <ElInputNumber                  :model-value="getNum(v, 'residual_price')"                  :controls="false"                  size="small"                  @update:model-value="(val) => setNum(v.id, 'residual_price', Number(val))"                />              </td>              <td class="fs-edit-cell">                <ElInputNumber                  :model-value="getExpectedResidual(v)"                  :controls="false"                  size="small"                  @update:model-value="                    (val) => setOverride(v.id, 'expected_residual_override', Number(val))                  "                />              </td>              <td v-if="isService">{{ computeTotals(v).svcTotal.toFixed(2) }}</td>              <td class="fs-edit-cell fs-amount">                <ElInputNumber                  :model-value="getVehicleTotal(v)"                  :controls="false"                  size="small"                  @update:model-value="(val) => setOverride(v.id, 'total_override', Number(val))"                />              </td>              <td class="fs-edit-cell">                <ElInput                  :model-value="getStr(v, 'modify_note')"                  size="small"                  @update:model-value="(val) => setStr(v.id, 'modify_note', val)"                />              </td>              <td>                <ElButton link type="danger" @click="removeVehicle(v.id)">移除</ElButton>              </td>            </tr>            <tr>              <td :colspan="isService ? 7 : 6" style="font-weight: 700; text-align: right"                >合计总金额</td              >              <td class="fs-amount">{{ grandTotal.toFixed(2) }}</td>              <td colspan="2" />            </tr>          </tbody>        </table>        <div class="fs-create-tip-row">★ 黄色字段可手动填写，其他字段只读或自动计算</div>      </div>    </template>    <template #footer>      <div v-if="step === 1 && billType" class="fs-create-footer-inner">        <span />        <div>          <ElButton @click="dialogVisible = false">关闭</ElButton>          <ElButton type="primary" @click="goStep2"            >下一步（已选 {{ selectedIds.size }} 辆）</ElButton          >        </div>      </div>      <div v-else-if="step === 2 && billType" class="fs-create-footer-inner">        <ElButton @click="step = 1">← 返回选车</ElButton>        <div>          <ElButton @click="dialogVisible = false">关闭</ElButton>          <ElButton type="primary" :loading="submitting" @click="handleSubmit"            >确认提交申请</ElButton          >        </div>      </div>    </template>  </ElDialog></template><script setup lang="ts">  import { ElMessage } from 'element-plus'  import {    fetchSettlementBillCreate,    fetchSettlementVehicleCandidates  } from '@/api/recycle/finance-settlement.mock'  import type {    SettlementBillLineItem,    SettlementBillType  } from '@/types/recycle/finance-settlement'  import { SETTLEMENT_BILL_TYPE_CONFIG } from '@/types/recycle/finance-settlement'  import type {    SettlementVehicleCandidate,    SettlementVehicleEdit  } from '@/types/recycle/finance-settlement-candidate'  import ArtSvgIcon from '@/components/core/base/art-svg-icon/index.vue'  const props = defineProps<{    visible: boolean    billType: SettlementBillType | null  }>()  const emit = defineEmits<{    'update:visible': [boolean]    success: []  }>()  const dialogVisible = computed({    get: () => props.visible,    set: (v) => emit('update:visible', v)  })  const step = ref<1 | 2>(1)  const search = ref('')  const candidates = ref<SettlementVehicleCandidate[]>([])  const selectedIds = ref(new Set<string>())  const edits = ref<Record<string, SettlementVehicleEdit>>({})  const submitting = ref(false)  const isService = computed(() => props.billType === '服务费结算单')  const filteredCandidates = computed(() => {    const q = search.value.trim()    return candidates.value.filter(      (v) => !q || v.plate.includes(q) || v.self_no.includes(q) || v.vehicle_model.includes(q)    )  })  const selectedVehicles = computed(() =>    candidates.value.filter((v) => selectedIds.value.has(v.id))  )  const allChecked = computed(    () =>      filteredCandidates.value.length > 0 &&      filteredCandidates.value.every((v) => selectedIds.value.has(v.id))  )  const someChecked = computed(() =>    filteredCandidates.value.some((v) => selectedIds.value.has(v.id))  )  const grandTotal = computed(() =>    selectedVehicles.value.reduce((s, v) => s + getVehicleTotal(v), 0)  )  function stepClass(s: number) {    if (step.value === s) return 'is-active'    if (step.value > s) return 'is-done'    return ''  }  function getNum(v: SettlementVehicleCandidate, key: keyof SettlementVehicleCandidate) {    const e = edits.value[v.id]    const ek = key as keyof SettlementVehicleEdit    if (e && e[ek] !== undefined && typeof e[ek] === 'number') return e[ek] as number    return v[key] as number  }  function getStr(v: SettlementVehicleCandidate, key: 'modify_note') {    return edits.value[v.id]?.[key] ?? v[key]  }  function setNum(vid: string, key: keyof SettlementVehicleEdit, val: number) {    edits.value = { ...edits.value, [vid]: { ...edits.value[vid], [key]: val } }  }  function setStr(vid: string, key: 'modify_note', val: string) {    edits.value = { ...edits.value, [vid]: { ...edits.value[vid], [key]: val } }  }  function setOverride(    vid: string,    key: 'expected_residual_override' | 'total_override',    val: number  ) {    edits.value = { ...edits.value, [vid]: { ...edits.value[vid], [key]: val } }  }  function computeTotals(v: SettlementVehicleCandidate) {    const actualW = getNum(v, 'actual_weight')    const rp = getNum(v, 'residual_price')    const sp = getNum(v, 'shortfall_parts')    const svc = getNum(v, 'svc_per_ton')    const strans = v.self_transport    const finalWaiver = sp * 40    const actualRes = actualW * rp - finalWaiver    const svcTotal = actualW * svc    const autoTotal = isService.value ? strans + svcTotal : strans + actualRes    return { finalWaiver, actualRes, svcTotal, autoTotal }  }  function getExpectedResidual(v: SettlementVehicleCandidate) {    const ov = edits.value[v.id]?.expected_residual_override    return ov !== undefined ? ov : computeTotals(v).actualRes  }  function getVehicleTotal(v: SettlementVehicleCandidate) {    const ov = edits.value[v.id]?.total_override    return ov !== undefined ? ov : computeTotals(v).autoTotal  }  function toggleVehicle(id: string) {    const next = new Set(selectedIds.value)    if (next.has(id)) next.delete(id)    else next.add(id)    selectedIds.value = next  }  function toggleAll(val: boolean | string | number) {    selectedIds.value = val ? new Set(filteredCandidates.value.map((v) => v.id)) : new Set()  }  function removeVehicle(id: string) {    const next = new Set(selectedIds.value)    next.delete(id)    selectedIds.value = next    if (!next.size) step.value = 1  }  function goStep2() {    if (!selectedIds.value.size) {      ElMessage.warning('请至少选择一辆车')      return    }    step.value = 2  }  async function onOpened() {    step.value = 1    search.value = ''    selectedIds.value = new Set()    edits.value = {}    candidates.value = await fetchSettlementVehicleCandidates()  }  function buildLineItems(): SettlementBillLineItem[] {    return selectedVehicles.value.map((v, i) => {      const c = computeTotals(v)      return {        seq: i + 1,        entry_date: v.inbound_date,        self_no: v.self_no,        plate: v.plate,        vehicle_model: v.vehicle_model,        vehicle_type: v.vehicle_type,        settle_type: v.settle_type,        std_weight: v.std_weight,        actual_weight: getNum(v, 'actual_weight'),        self_delivery_subsidy: v.self_transport,        missing_part_tonnage: getNum(v, 'shortfall_weight'),        residual_unit_price: getNum(v, 'residual_price'),        missing_part_amt: getNum(v, 'shortfall_parts'),        hub_material: v.hub_material,        deduction: getNum(v, 'deduction'),        missing_part_exempt: c.finalWaiver > 0 ? '是' : '否',        expected_residual: Math.round(getExpectedResidual(v)),        ...(isService.value          ? {              service_fee_per_ton: getNum(v, 'svc_per_ton'),              service_fee_total: Math.round(c.svcTotal)            }          : {}),        total_per_vehicle: Math.round(getVehicleTotal(v)),        modify_note: getStr(v, 'modify_note'),        qc_missing_note: v.qc_missing_note,        review_status: '待审核'      }    })  }  async function handleSubmit() {    if (!props.billType || !selectedVehicles.value.length) return    submitting.value = true    try {      const isSvc = props.billType === '服务费结算单'      const newId = `NEW-${Date.now()}`      const dateStr = new Date().toISOString().slice(0, 10).replace(/-/g, '')      await fetchSettlementBillCreate({        settlement_type: props.billType,        contract_no: `${isSvc ? 'HS' : 'JSD'}${dateStr}${String(Math.floor(Math.random() * 9000) + 1000)}`,        order_no: `DD${newId}`,        charge_type: isSvc ? '报废服务费' : '残值回收',        applicant: '当前用户',        apply_time: new Date().toLocaleString('zh-CN').replace(/\//g, '-'),        amount: Math.round(grandTotal.value),        items: buildLineItems()      })      ElMessage.success('申请已提交')      dialogVisible.value = false      emit('success')    } finally {      submitting.value = false    }  }</script><style scoped lang="scss">  @use './settlement-dialog';  .fs-create-header-title {    font-size: 15px;    font-weight: 700;  }  .fs-create-close {    display: flex;    padding: 4px;    font-size: 20px;    color: rgb(255 255 255 / 85%);    cursor: pointer;    background: none;    border: none;    &:hover {      color: #fff;    }  }  .fs-create-selected-hint {    margin-left: auto;    font-size: 12px;    color: #9ca3af;    b {      color: #4169ff;    }  }  .fs-create-row {    cursor: pointer;  }</style>